#include <stdio.h>
#include <stdlib.h>

int canAllocate(long long *books, int n, int a, long long limit) {
    int students = 1;
    long long cur = 0;
    for (int i = 0; i < n; ++i) {
        if (books[i] > limit) return 0;
        if (cur + books[i] > limit) {
            ++students;
            cur = books[i];
            if (students > a) return 0;
        } else {
            cur += books[i];
        }
    }
    return 1;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, A; scanf("%d %d", &N, &A);
        long long *books = (long long*)malloc(N * sizeof(long long));
        long long lo = 0, hi = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &books[i]);
            if (books[i] > lo) lo = books[i];
            hi += books[i];
        }
        long long ans = hi;
        while (lo <= hi) {
            long long mid = lo + (hi - lo) / 2;
            if (canAllocate(books, N, A, mid)) {
                ans = mid;
                hi = mid - 1;
            } else {
                lo = mid + 1;
            }
        }
        printf("%lld\n", ans);
        free(books);
    }
    return 0;
}

