import sys

def feasible(books, a, limit):
    students = 1
    cur = 0
    for pages in books:
        if pages > limit:
            return False
        if cur + pages > limit:
            students += 1
            cur = pages
            if students > a:
                return False
        else:
            cur += pages
    return True

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); A = int(next(it))
        books = [int(next(it)) for _ in range(N)]
        lo = max(books)
        hi = sum(books)
        ans = hi
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(books, A, mid):
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

